                        { label: 'Yan', val: 40 }, { label: 'Fev', val: 75 }, { label: 'Mar', val: 60 }, 
                        { label: 'Apr', val: 90 }, { label: 'May', val: 100 }, { label: 'Iyun', val: 85 }
                      ].map((bar, i) => (
                        <div key={i} style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '12px' }}>
                          <motion.div 
                            initial={{ height: 0 }}
                            animate={{ height: `${bar.val}%` }}
                            transition={{ duration: 1, delay: i * 0.1 }}
                            style={{ width: '100%', background: i === 4 ? 'var(--primary)' : '#E0E7FF', borderRadius: '8px', minHeight: '4px' }}
                          ></motion.div>
                          <span style={{ fontSize: '12px', color: '#86868b' }}>{bar.label}</span>
